import{_ as s,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse(`{"title":"Inside Claude Code: Coordinators and Swarms","description":"Claude Code's two multi-agent modes: a coordinator with disposable workers, and a swarm of teammates in terminal panes.","frontmatter":{"description":"Claude Code's two multi-agent modes: a coordinator with disposable workers, and a swarm of teammates in terminal panes.","date":"2026-05-07","tags":["Claude Code","Multi-Agent"]},"headers":[],"relativePath":"blog/inside-claude-code/multi-agent-swarm.md","filePath":"en/blog/inside-claude-code/multi-agent-swarm.md","lastUpdated":1780484238000}`),n={name:"blog/inside-claude-code/multi-agent-swarm.md"};function o(r,e,h,l,d,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="inside-claude-code-coordinators-and-swarms" tabindex="-1">Inside Claude Code: Coordinators and Swarms <a class="header-anchor" href="#inside-claude-code-coordinators-and-swarms" aria-label="Permalink to &quot;Inside Claude Code: Coordinators and Swarms&quot;">​</a></h1><p>A single agent has a hard ceiling. Its context fills up, and it does one thing at a time. The obvious escape is more agents — but &quot;more agents&quot; is where most multi-agent frameworks turn into a tangle of message buses and orchestration DSLs.</p><p>Claude Code has two multi-agent modes in the source, and both are refreshingly low-ceremony. One is a <strong>coordinator</strong> that fans work out to ephemeral workers; the other is a <strong>swarm</strong> of persistent teammates that each live in their own terminal pane. Both are gated behind experimental flags (<code>COORDINATOR_MODE</code> and the swarm feature gates), so neither is on by default — but they&#39;re a clear window into where the harness is heading.</p><h2 id="coordinator-mode" tabindex="-1">Coordinator mode <a class="header-anchor" href="#coordinator-mode" aria-label="Permalink to &quot;Coordinator mode&quot;">​</a></h2><p>Flip on <code>COORDINATOR_MODE</code> and set <code>CLAUDE_CODE_COORDINATOR_MODE=1</code>, and the main agent&#39;s whole personality changes. It stops doing the work and starts directing it:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;">// coordinatorMode.ts</span></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">export</span><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;"> function</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> isCoordinatorMode</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">():</span><span style="--shiki-light:#2E8F82;--shiki-dark:#5DA994;"> boolean</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> {</span></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">  if</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> (</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">feature</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">COORDINATOR_MODE</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">))</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> {</span></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">    return</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> isEnvTruthy</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">process</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">.</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">env</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">.</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">CLAUDE_CODE_COORDINATOR_MODE</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">);</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">  }</span></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">  return</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> false</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">;</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">}</span></span></code></pre></div><p>The coordinator&#39;s system prompt is blunt about the new role: <em>&quot;You are a <strong>coordinator</strong>. Direct workers to research, implement and verify code changes. Synthesize results and communicate with the user.&quot;</em> It gets exactly three orchestration tools — <code>Agent</code> (spawn a worker), <code>SendMessage</code> (continue an existing worker by its agent ID), and <code>TaskStop</code> (stop one going the wrong way).</p><p>The interaction model is fully <strong>asynchronous</strong>. The coordinator launches workers, tells the user what it launched, and <em>ends its turn</em>. It never blocks waiting. Worker results come back later as user-role messages wrapped in a <code>&lt;task-notification&gt;</code> envelope:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">task-notification</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">  &lt;</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">task-id</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">agent-a1b</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;/</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">task-id</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">  &lt;</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">status</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">completed|failed|killed</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;/</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">status</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">  &lt;</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">summary</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">Agent &quot;Investigate auth bug&quot; completed</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;/</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">summary</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">  &lt;</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">result</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">Found null pointer in src/auth/validate.ts:42...</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;/</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">result</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">&lt;/</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">task-notification</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">&gt;</span></span></code></pre></div><p>There&#39;s a sharp instruction about how to treat these:</p><blockquote><p>Worker results and system notifications are internal signals, not conversation partners — never thank or acknowledge them.</p></blockquote><p>The work is organized into phases, and the only one the coordinator does itself is the thinking:</p><table tabindex="0"><thead><tr><th>Phase</th><th>Who</th><th>Purpose</th></tr></thead><tbody><tr><td>Research</td><td>Workers (parallel)</td><td>Investigate, find files, understand the problem</td></tr><tr><td>Synthesis</td><td><strong>Coordinator</strong></td><td>Read findings, craft implementation specs</td></tr><tr><td>Implementation</td><td>Workers</td><td>Make targeted changes, commit</td></tr><tr><td>Verification</td><td>Workers</td><td>Prove the changes work</td></tr></tbody></table><p>Concurrency here is the same read/write discipline from the <a href="./read-write-concurrency-separation">tool execution layer</a>, lifted up to the agent level: <em>&quot;Parallelism is your superpower. Workers are async.&quot;</em> Read-only research fans out freely; write-heavy implementation runs one worker at a time per set of files. And <code>SendMessage</code> lets the coordinator continue a worker whose task is done to reuse its already-warm context, rather than paying to spin up a fresh one.</p><h2 id="the-rule-against-handing-off-understanding" tabindex="-1">The rule against handing off understanding <a class="header-anchor" href="#the-rule-against-handing-off-understanding" aria-label="Permalink to &quot;The rule against handing off understanding&quot;">​</a></h2><p>The most interesting line in the coordinator prompt isn&#39;t about mechanics — it&#39;s about responsibility:</p><blockquote><p>Never write &quot;based on your findings&quot; or &quot;based on the research.&quot; These phrases delegate understanding to the worker instead of doing it yourself. You never hand off understanding to another worker.</p></blockquote><p>Because workers can&#39;t see the coordinator&#39;s conversation, every worker prompt has to be self-contained — specific file paths, line numbers, exactly what to change. That forces the coordinator to actually digest each research result before directing the next step, instead of playing telephone. The verification phase carries the same skepticism: <em>&quot;Verification means proving the code works, not confirming it exists. A verifier that rubber-stamps weak work undermines everything.&quot;</em></p><p>It&#39;s a multi-agent design that spends its prompt budget guarding against the classic failure mode — a swarm of agents that each assume someone else understood the problem.</p><h2 id="swarms-teammates-in-panes" tabindex="-1">Swarms: teammates in panes <a class="header-anchor" href="#swarms-teammates-in-panes" aria-label="Permalink to &quot;Swarms: teammates in panes&quot;">​</a></h2><p>The second mode is heavier and more literal. Instead of ephemeral workers reporting back through notifications, a <strong>swarm</strong> is a set of persistent, named teammates — and each one runs in its own terminal pane. The <code>utils/swarm/backends/</code> directory has interchangeable pane backends for <strong>tmux</strong>, <strong>iTerm</strong>, and an in-process variant, with a leader pane coordinating the rest.</p><p>Teammates talk to each other through a dead-simple, file-based mailbox:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>// teammateMailbox.ts</span></span>
<span class="line"><span>// Each teammate has an inbox at:</span></span>
<span class="line"><span>//   .claude/teams/{team_name}/inboxes/{agent_name}.json</span></span>
<span class="line"><span>// Other teammates write messages to it; the recipient sees them as attachments.</span></span></code></pre></div><p>No broker, no socket protocol for the messages themselves — just JSON files in a known directory, with the same <code>SendMessage</code> tool driving delivery. <code>TeamCreate</code> and <code>TeamDelete</code> manage the lifecycle. It&#39;s the kind of design that sounds too simple until you remember that &quot;a file in a shared directory&quot; is one of the most robust IPC mechanisms ever invented.</p><h2 id="the-takeaway" tabindex="-1">The Takeaway <a class="header-anchor" href="#the-takeaway" aria-label="Permalink to &quot;The Takeaway&quot;">​</a></h2><p>These are two genuinely different shapes of multi-agent system. The coordinator is <strong>hub-and-spoke</strong>: one brain, disposable hands, async notifications, and a hard rule that the brain never delegates its understanding. The swarm is a <strong>peer team</strong>: durable agents with names and inboxes, parked in real terminal panes you can watch.</p><p>What they share is the refusal to build a framework. The coordinator is a system prompt plus three tools. The swarm&#39;s messaging is JSON files in <code>.claude/teams/</code>. The hard parts — parallelism rules, self-contained prompts, real verification, not thanking the robots — live in prose the model is told to follow, not in orchestration machinery. It&#39;s the same bet the rest of the codebase makes: give the model a clear contract and a few sharp tools, and let it coordinate.</p>`,27)])])}const g=s(n,[["render",o]]);export{c as __pageData,g as default};
